import{_ as s,I as t,o as n,c as b,a4 as r,j as l,a as i,J as p,w as a}from"./chunks/framework.EYT3XhWU.js";const v=JSON.parse('{"title":"词义辨析","description":"","frontmatter":{},"headers":[],"relativePath":"行测/言语理解/逻辑填空/词义辨析.md","filePath":"行测/言语理解/逻辑填空/词义辨析.md"}'),x={name:"行测/言语理解/逻辑填空/词义辨析.md"},d={class:"details custom-block",open:"",style:{"box-sizing":"border-box",border:"1px solid rgba(0, 0, 0, 0)","border-radius":"8px",padding:"16px 16px 8px","line-height":"24px","font-size":"16px",color:"rgb(223, 223, 214)","background-color":"rgba(142, 150, 170, 0.14)",margin:"0px !important"}},g={start:"4",style:{"box-sizing":"border-box","list-style":"decimal",margin:"16px 0px",padding:"0px 0px 0px 1.25rem"}},_={style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}};function w(y,o,m,c,z,k){const e=t("font");return n(),b("div",null,[o[8]||(o[8]=r('<h1 id="词义辨析" tabindex="-1">词义辨析 <a class="header-anchor" href="#词义辨析" aria-label="Permalink to “词义辨析”">​</a></h1><p>字数: 8452 字 时长: 31 分钟 <strong>VIP文档</strong></p><h2 id="一、形近词、音近词" tabindex="-1">一、形近词、音近词 <a class="header-anchor" href="#一、形近词、音近词" aria-label="Permalink to “一、形近词、音近词”">​</a></h2><ol><li><p><strong>1、题型特征</strong>：选项中的词语不仅字形相近，有的甚至连发音都相同，例如“推脱”和“推托”但用法不同。这类题目比较具有迷惑性，难度较高。</p></li><li><p><strong>2、解题思路</strong>：组词法、拆分法。</p><ol><li><p>（1）组词法</p><p>：组词是指和其他词句搭配在一起理解。</p><ol><li><code>例</code>：“推脱”和“推托”，我们常说 “推脱责任“ (必须做的事情，没有去做)， “推托请求” (不是必须做的事情，没有去做)。</li><li><code>例</code>：“风景”和“景物”，风景=风光+景色，一般是指大自然自然形成的风光；景物=景色+物体，特指构成景色的物体；</li></ol></li><li><p>（2）拆分法</p><p>：拆分是指将词语拆分出单个的字去理解。</p><ol><li><code>例</code>：“精巧” 和 “精致” ， “巧” 侧重在强调巧妙、玲珑； “致”，侧重强调别致、新奇。</li><li><code>例</code>：“消亡” 和 “灭亡” ，消亡的 “消” 强调有一个消失的过程，而灭亡的 “灭” 则不强调过程，例如恐龙灭亡，可以是一瞬间的事情；因此它们程度有区别。</li><li><code>例</code>：“缘木求鱼”，“缘”含义是沿着、顺着，“木”指的是木头，“求”是寻找，“鱼”就是动物的鱼，所以“缘木求鱼”指的是顺着木头去找鱼，也就是说这个方法是没有用的，达不到目的。</li></ol></li></ol></li></ol><p><strong>例</strong>：(2015 国考)作为全国最高的货币管理机构，央行独具优势，拥有 “惯看秋月春风”的______ ，由此而一展 “任凭风浪起，稳坐钓鱼台” 的 “定力” 是毫无疑问的。不过，一旦说到的 “精准发力” ，央行究竟是为了稳定预测，还是真的自信能 “精确打击” ，倒是值得_______一番的。</p><ol><li>依次填入画横线部分最恰当的一项是()</li><li>A.气度 琢磨  B.气概 捉摸</li><li>C.气质 期待  D.气派 商榷</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="7" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">A 项 “气度” 的 “度” 可组词 “风度” “大度” “度量” 等，与原文 “惯看秋月春风” 及后文的 “定力” 相对应，表现出 “作为全国最高的货币管理机构” 的气定神闲。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B 项 “气概” 可以组词为 “英雄气概” ，可见 “气概” 常用以表达勇敢气魄，与原文语义不符，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项 “气质” 可以组词为 “领袖气质” 、 “淑女气质” 等，主要表达一种个性特征，不能用 “惯看秋月春风” 来形容，故排除;</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项 “气派” 的 “派” 组词为 “派头” ，常用于形容气质或者形容神气的样子，不如A项 “气度” 恰当。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二空， “琢磨” 意为反复思考，即对央行精准发力的目的和效果这一问题需要反复思考，语义恰当。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为 A。</li></ol></details><p><strong>例</strong>：（2017广州）在养老举措、制度设计等各方面______更多“老吾老以及人之老”的同理心，是一座城市、一个社会对待老年人应有的温情与敬意。</p><ol><li>填入下列横线处的词语，最恰当的一项是：</li><li>A.灌注</li><li>B.灌溉</li><li>C.灌输</li><li>D.灌制</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">看选项，发现这四个词都是“灌X”的形式，看到这种选项的时候，可以运用词语拆分法，把词语中相同的字划掉，ABCD项分别留下：注、溉、输、制。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第一步，空所修饰的词是同理心，B可以首先排除，根据常识，灌溉是浇灌农作物，和同理心不搭配。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二步，对比另外三个字的差别：注、输、制。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">分别进行组词：[注入，注意]、[输入]、[制作]。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">其中注入和输入都是从外到内运送，而注入强调的运送专注于一个点；输入强调的是运送这个动作；制作是从无到有，产生某个东西。可以容易排除D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第三步，阅读文段，文段着重说在养老举措、制度设计要增加同理心，着重点在同理心上，强调的是灌入的那个点，而不是输入这个动作，所以选A。</li></ol></details><p><strong>例</strong>：（2018安徽蚌埠事业单位）对于外星人的想象并不是凭空_____的，丰富的想象来源于知识的广博和平时对生活深入、细致的观察。观察就要用专业的角度去关注、_______周围的事物，有意识地汲取、思索、分析，看在眼里，记在心里。</p><ol><li>填入画横线部分最恰当的一项是（ ）。</li><li>A.捏造　体验</li><li>B.虚构　体味</li><li>C.杜撰　体会</li><li>D.臆造　体察</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">本题可从第二空入手，由“、”可知，待填词与“关注”构成并列，表示注意到周边事物，又由“观察”“看在眼里”可知，人们是用眼睛注意到周围事物的，待填词应表示看到之意。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项“体察”侧重“察”，可组词“观察”，强调观察、看到，符合文意，保留。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“体验”侧重“验”，可组词“经验”，强调亲身经历，未体现看到之意，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项“体味”侧重“味”，可组词“品味”，强调自我领悟、感受，未体现看到之意，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项“体会”侧重“会”，可组词“领会”，强调感受、领会，无看到之意，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第一空代入验证，“凭空臆造”搭配得当，体现出对于外星人的想象不是虚假的，当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故本题答案为D项。</li></ol></details><p><strong>例</strong>：（2021甘肃）节约资源、减少垃圾生产成为某种意义上的公共事务，很容易遭遇“搭便车困境”——人人都想________，最终会导致公共事务乏人问津。节约资源的功效并没有那么_______，需要人们久久为功；付出没有得到及时、有效的反馈与回报，难免会影响公众参与。</p><ol><li>依次填入画横线部分最恰当的一项是：</li><li>A.蜂拥而上 妙手回春</li><li>B.鸠占鹊巢 神通广大</li><li>C.据为己有 一劳永逸</li><li>D.坐享其成 立竿见影</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">第一空，由破折号可知，所填词语是对“搭便车困境”的解释说明。“搭便车”本义为自己不想开车，所以乘坐他人的便车；引申义为，自己不想付出努力而去享受他人带来的便利。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B和C通过拆词“占”、“据”，理解为把别人的占据为自己所拥有。而“搭便车”只是“搭”不是“抢”。排除B、C。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">而蜂拥而上通过拆词，每个词都体现不了自己不出力，享受他人成果的意思，不符合文意，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二空，代入验证，根据“并没有······需要······”可知，横线处与后文“久久为功”语义相反，体现“时间短”之意。D项“立竿见影”指见效快，符合文意，当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><h2 id="二、固定搭配" tabindex="-1">二、固定搭配 <a class="header-anchor" href="#二、固定搭配" aria-label="Permalink to “二、固定搭配”">​</a></h2><ol><li>考查主要集中在日常生活用语的习惯搭配和一些专业领域里特殊用语的固定搭配上。这一类题通常没有太多技巧可言，主要靠我们平时多阅读、多积累 。有些词语虽然基本意思相同，但是由于人们的使用习惯不同，有的经常与某些词语搭配使用，有的则不能与某些词语搭配使用，从而形成了比较固定的格式。 <ol><li><code>比如</code>：“严厉”常与“打击”、“制裁”、“批评”等词语搭配。</li><li><code>比如</code>：“严格”常与“要求”、“遵守”、“执行”等词语搭配</li><li><code>比如</code>：“严密”常与“防守”、“监控”、“调查”等词语搭配</li></ol></li><li><strong>1、题型特征</strong>：选项和题干中有常见常用的固定搭配。</li><li><strong>2、解题思路</strong>： <ol><li>（1）根据词性找搭配：注意主语、谓语、宾语的搭配 <ol><li>①若选项都是动词，回到文段找与之搭配的主语名词和宾语名词。</li><li>②若选项都是名词，回到文段找与之搭配的谓语动词或形容词。</li></ol></li><li>（2）注意新闻热点、时事评论、人民日报中常用词搭配的积累 <ol><li>①积累常用词，例如：爱护环境/爱惜羽毛、人烟稀少/资源稀缺</li><li>②积累热点词，例如：经济新常态、供给侧结构性改革、京津协同发展。</li><li>③当出现 “和” “及” “与” 引导的并列结构时，可能要求所填词语能够搭配多个词语</li></ol></li></ol></li></ol><p><strong>例</strong>：（2018吉林法院）人文教育的重要目的在于使学生经由大学教育，能够_______纯粹功利的职业取向，_______狭隘的专业意识，从细小的专业分支中走出来。</p><ol><li>填入横线部分最恰当的一项是（ ）。</li><li>A.抵制 扭转</li><li>B.制止 克服</li><li>C.抵制 克服</li><li>D.制止 扭转</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="6" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">第一空中，“制止”与“取向”搭配不当，故排除B、D。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二空中，与“意识”搭配，一般用“克服”。故本题选C。</li></ol></details><p><strong>例</strong>：（2018江苏）湿地拥有独特的自然景观美。湿地的自然景观是湿地自然而然、自足自得的自然之性的_______，是大自然的________造就的自然生态平衡之美。</p><ol><li>依次填入画横线处最恰当的一项是（ ）</li><li>A. 彰显  鬼斧神工</li><li>B. 显现  沧海桑田</li><li>C. 凸显  开天辟地</li><li>D. 展现  精雕细琢</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="7" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">本题可从第二空入手 , 横线处搭配“大自然”，表示湿地之美是大自然造就的 ，自然而生的语义，对应选项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A 项“鬼斧神工”形容艺术技巧高超，不是人力所能达到的，与 “大自然” 搭配恰当，符合文段语境，当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B 项 “沧海桑田” 比喻人世间事物变化极大，或者变化较快。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C 项 “开天辟地” 表示有史以来的，均与文段语义无关，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D 项 “精雕细琢” 比喻做事情精益求精，认真细致，一般搭配主体为人，与“大自然”搭配不当，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第一空 , 代入验证，“彰显” 指明显、显著，鲜明地显示，表达 “湿地是大自然之美的体现”，且与前文 “湿地拥有独特的自然景观美” 相对应，符合文段语境。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为 A。</li></ol></details><p><strong>例</strong>：（2019辽宁）散布谣言者抓住人们“宁可信其有不可信其无”的心理，散布________的网络谣言。这些谣言误导了公共舆论，<strong><strong><strong>了社会秩序，影响了人们的正常生活。不仅会造成人心恐慌，有的还会给行业和产业发展带来巨大损失，甚至也使国家的一些好政策遭到误解，严重影响政府公信力，民众对此</strong></strong></strong>_。</p><ol><li>依次填入画横线部分最恰当的一项是：</li><li>A.捕风捉影 扰乱 嗤之以鼻</li><li>B.骇人听闻 干扰 莫衷一是</li><li>C.耸人听闻 妨碍 不屑一顾</li><li>D.危言耸听 扰乱 深恶痛绝</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">读文段，第一空搭配“网络谣言”，既然是谣言一定是负面的，不好的，可以先看选项，从感情色彩出发，看是否有可以排除的选项；发现不可以，选项都是负面的，都可以形容谣言，但是语义轻重程度不同；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二空与“社会秩序”搭配，“扰乱”社会秩序是我们的常见搭配，所以我们可以排除B和C；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第三空：造成恐慌、带来巨大损失、还用“甚至”递进了一下，说明坏的影响加剧，好政策遭误解，严重影响公信力，那民众会是什么态度呢？这句话中的语义就比较重了，嗤之以鼻与深恶痛绝明显后者更重，选D。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><p><strong>例</strong>：（2009河北）①深圳女孩黄慧_______的脊髓植入广西男中学生程金波体内，这是内地首例非亲缘异性间骨髓移植的手术。 ②社会实践的继续，使人们在实践中引起感觉和印象的东西_______出现，于是人们头脑里便发生了一个认识的突变，产生了概念。 ③肖老比我年长30岁，他无愧为我们的师长。每次相见，我都以晚辈、学生的身份向他请教，带着几分_______。</p><ol><li>依次填入划横线部分最恰当的一组是：</li><li>A.捐赠 重复 拘谨</li><li>B.捐献 反复 拘谨</li><li>C.捐赠 反复 拘束</li><li>D.捐献 重复 拘束</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="6" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">第一空，搭配骨髓；“捐赠”后一般搭配的是礼物、纪念品等，“捐献”指舍弃、献出财物等。这儿应填“捐献”，因此排除A、C两项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二空，“重复”指按照原样再来一次，也可是多次；“反复”指一遍又一遍，多次重复。所以选“反复”，因此排除D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第三空，“拘谨”侧重于因过分谨慎而表现为小心翼翼，主要指内心活动，多用于书面语；“拘束”侧重于因自我过分约束而放不开，主要指外在表现，通用于口语和书面语。这里应该是内心活动，所以填“拘谨”。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><h2 id="三、程度轻重" tabindex="-1">三、程度轻重 <a class="header-anchor" href="#三、程度轻重" aria-label="Permalink to “三、程度轻重”">​</a></h2><ol><li><strong>1、题型特征</strong>：词义的轻重往往表现在近义词中，常与递进关联词（<code>更、甚至、乃至、直至、尤其...</code>）结合考查。</li><li><strong>2、解题思路</strong>：有些含义相近的词语在词义上会有轻重不同，需要结合题干信息进行辨析。所填词语的程度轻重与文段意思的程度轻重要保持一致，避免“过轻”或“过重”。 <ol><li><code>例</code>: “失望” 和 “绝望” ，都表示不能够满足的意思， “失望” 指失去了希望； “绝望” 彻底的不再抱有希望。所以 “失望” 程度较轻。</li><li><code>例</code>: “损坏” 和 “毁坏” ， “损坏” 指程度较轻的破坏、损失， “毁坏” 指性质较严重的破坏。所以 “毁坏” 程度较重。</li></ol></li><li><strong>3、注意</strong>：如果是递进，则前轻后重；如果是并列，则程度一致。</li></ol><p><strong>例</strong>：(2014国考) “假说” 在没有事实验证的情况下还不是科学理论。现有的科学知识和理论远不是事实的全部，而我们的许多科学家在从事研究工作时，总是_______于现有的一些学说，只是试图用实验结果来证明这些假说的合理性，而不是设法去________它。实际上，许多流行的假说与科学理论必须符合客观实际、逻辑严谨、没有矛盾的要求，_________。</p><ol><li>依次填入画横线部分最恰当的一项是（ ）。</li><li>A.受制 反驳 背道而驰  B.局限 排斥 针锋相对</li><li>C.纠结 求证 大相径庭  D.拘泥 否定 相去甚远</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="7" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">第一空，C项 “纠结” 一词过于口语化，且与“学说”搭配不当，故排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二空从 “只是……而不是……” 的反义并列可知，空格处应填的词与 “证明” 语义相反，且搭配 “它“(假说)，故排除B项 “排斥” 。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第三空，对比A、D两项可知， “背道而驰” 与 “相去甚远” 二者的程度不同，前者表示完全相反，后者仅表示差别比较大。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">结合文段材料，A项 “背道而驰” 意味着这些流行的假说是 “不符合客观实际” “没有逻辑” “前后矛盾” ，这种表述过于严重，因此排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为 D。</li></ol></details><p><strong>例</strong>：（2016重庆）诗歌，这一文学皇冠上最古老而璀璨的明珠，在当代社会正面临着前所未有的境况。一面是大众偏见的_________，譬如“诗歌就是分行”“写诗是无病呻吟”等论调甚嚣尘上；一面是诗歌内部的_________，学术话语与商业话语分庭抗礼，业内与大众水火不容。</p><ol><li>依次填入划横线部分最恰当的一项是：</li><li>A. 蔓延 抵触</li><li>B. 流行 分歧</li><li>C. 横行 分裂</li><li>D. 干扰 争议</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">第一空，横线后提到“论调甚嚣尘上”，说明这些“大众偏见”普遍流传，传播很广，D项“干扰”有打扰、妨碍的意思，不能体现传播很广，故排除D项；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二空，横线后提到“分庭抗礼”“水火不容”，程度较重，说明诗歌内部分成两个部分，完全不能相容，对应C项“分裂”，A项“抵触”强调有矛盾，B项“分歧”指意见不一致，“抵触”与“分歧”相对于“分裂”来说程度太轻，不能体现出完全不相容的状态，故排除A、B两项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为C。</li></ol></details><p><strong>例</strong>：（2021国家）信息匮乏的年代，决策水平与信息量成正相关，但当信息从匮乏走向过载甚至爆炸时，决策质量与信息量间的函数曲线便开始下滑，利用繁杂信息形成________判断变得难上加难，此时，智能化就可以大显身手。计算智能未必能在逻辑能力上逾越人类，但其强大的处理速度却恰好使信息过载带来的决策困境________。</p><ol><li>依次填入画横线部分最恰当的一项是：</li><li>A. 理性 烟消云散  B. 准确 迎刃而解</li><li>C. 科学 不复存在  D. 有效 无影无踪</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="3" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">突破口在第二空。根据“智能化就可以大显身手”和转折词“但”能够看出，该空要与“决策困境”搭配，且体现出计算智能能够解决信息过载带来的问题。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项“迎刃而解”指主要问题解决了，其他有关的问题就很容易解决，符合文意。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“烟消云散”比喻事物消失得干干净净；C项“不复存在”指不会再次出现或拥有；D项“无影无踪”指没有一点踪影，形容完全消失，不知去向；这三项均在强调问题彻底不存在，而文段强调的是问题能够被解决，而不是问题彻底不存在，故这三项均语义过重，排除，答案锁定B选项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">验证第一空。“利用繁杂信息形成准确判断变得难上加难”符合文段意思。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">因此，选择B选项。</li></ol></details><p><strong>例</strong>：（2016国家）关于枕头，现代人比前人的认识和经验都要多得多，但是人们记得最________的话，却是古人说的“高枕无忧”，现在被________最多的，恰恰也是这句话，“高枕”被认为是颈椎问题的诱因之一。</p><ol><li>依次填入划横线部分最恰当的一项是:</li><li>A. 深刻 指责   B. 清楚 批评</li><li>C. 牢固 谴责   D. 广泛 批判</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="3" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">第一步，分析第一空。填入的词应与“记得”搭配。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“深刻”指透彻、深入；B项“清楚”指清晰明白；C项“牢固”形容坚固、结实，三者均可与“记得”搭配，符合文意。D项“广泛”指(涉及的)方面广，范围大，普遍，与“记得”搭配不当，排除D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">分析第二空。搭配的是“高枕无忧”这句话，而古人说的这句话并非是为了害我们，只是基于当时的知识和经验所流传的一个说法而已，所以用“指责”和“谴责”均用词过重。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“指责”意为指出过失并责备；C项“谴责”指斥责、责备，二者均侧重于对重大过失的责备，不符合文意，排除A项和C项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项“批评”指评论、评判，对缺点错误提出意见，符合文意。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">因此，选择B选项。</li></ol></details><h2 id="四、感情色彩" tabindex="-1">四、感情色彩 <a class="header-anchor" href="#四、感情色彩" aria-label="Permalink to “四、感情色彩”">​</a></h2><ol><li><strong>1、词语的感情色彩</strong>：分为三种：褒义、贬义、中性。 <ol><li>（1）褒义词是指带有积极感情色彩的词语，适用于喜爱、肯定、尊敬等好语境中；</li><li>（2）贬义词是指带有消极感情色彩的词语，适用于贬斥、厌恶、否定、鄙视等坏的语境中；</li><li>（3）中性词是指不体现特殊感情色彩的词语，既可以用在好的方面，也可以用在坏的方面的词语。</li><li><code>例</code>：成果-结果-后果：成果一般搭配“科研成果、学习成果”，是比较积极的感情色彩，为褒义词。结果可好可坏，有好的结果，也有坏的结果，为中性词。后果一般指有害的或不幸的结果，带有消极感情色彩。</li><li><code>例</code>：趋之若鹜-争先恐后：趋之若鹜比喻许多人争着去追逐某些不好的事物，带有消极感情色彩。争先恐后指争着向前，唯恐落后，为中性词。</li><li><code>例</code>：不胜枚举-罄竹难书：不胜枚举指无法一一全举出来，形容数量很多，为中性词。罄竹难书形容罪行多得写不完，带有消极感情色彩。</li></ol></li><li><strong>2、题型特征</strong>：文段和选项中的词语有明显的感情倾向。</li><li><strong>3、解题思路</strong>：选项词语尤其是很多成语都有不同的感情色彩，通过材料中作者的观点态度，确定感情色彩的褒贬，即所填词语的感情色彩和文段的感情色彩要保持一致。比如 “粉墨登场” ，含贬义，只能用于某人物经过一番包装后登上政治舞台。</li><li><strong>4、注意</strong>：感情色彩还有一种特殊用法，即贬词褒用。就是采用说反话的方法，把带有贬斥、憎恶等贬义感情的词灵活运用，临时转化为赞许、表扬的感情。更具讽刺性，效果更突出。而贬词褒用，更需要仔细分析语境，常常用引号来提示。</li></ol><p><strong>例</strong>：（2015国考）相对于其他作品，史书有太多芜杂的琐碎记载，把主线_____得有些模糊不清。然而细节有细节的______之处，因为虽然撰写史书的史官难免受到某些思维导向的影响，有意无意地隐此扬彼，但所谓 “细节之中有魔鬼” ，某个历史人物的性格总会在一些细节之中_______。</p><ol><li>依次填入画横线部分最恰当的一项是（）</li><li>A.遮蔽 精妙 若隐若现  B.隐藏 奇巧 跃然纸上</li><li>C.衬托 精彩 昭然若揭  D.叙述 可爱 露出马脚</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="9" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">此题第三空为突破口。首先判断各选项词语的词性，A项 “若隐若现” 与B项 “跃然纸上” 均为中性词。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项 “昭然若揭” 常用以形容坏事、坏心思等非常清楚地显露出来；D项 “露出马脚” 意指暴露了隐蔽的事实真相或内情无意中泄露出来。C、D两项的语境偏向消极。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">然而文段仅为对史书的中性描述，并无明显的感情倾向，所以排除C、D。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">对比A、B两项，第一空用 “遮蔽” 搭配后文的 “模糊不清” 更为恰当， “隐藏” 侧重于藏起来找不到，而非模糊不清，由此排除B项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为 A。</li></ol></details><p><strong>例</strong>：（2018浙江丽水事业单位）早些年社会上造假之风就已______，站牌、电线杆等贴满了密密麻麻的非法小广告，身份证、文凭可以伪造。单位公章也可以仿造，就连伪造推荐信中的领导签字都可以达到______。</p><ol><li>填入横线部分最恰当的一项是（ ）。</li><li>A.大肆盛行　无与伦比</li><li>B.盛极一时　鱼目混珠</li><li>C.如日中天　惟妙惟肖</li><li>D.沉渣泛起　以假乱真</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="12" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">第一空，从后文站牌、电线杆等贴满了密密麻麻的非法小广告，身份证、文凭可以伪造可知，造假之风盛行。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“大肆盛行”指普遍流行，一般形容不好的事物，感情色彩消极，保留；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项“盛极一时”形容一时特别兴盛或流行，感情色彩积极，而造假之风为不好的事情，感情色彩应偏消极，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项“如日中天”指事物正发展到十分兴盛的阶段，感情色彩偏积极，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项“沉渣泛起”指已经绝迹了的腐朽、陈旧事物又重新出现，可以形容造假之风，含贬义，保留。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二空，A项“无与伦比”指没有比得上的，含褒义，而从文中伪造领导人签字可以，该处感情色彩偏消极，排除；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项“以假乱真”，指用假的东西去冒充或混杂真的东西，贬义，符合文意，当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为D。</li></ol></details><p><strong>例</strong>：（2020海南）国学如果停留在浅层次的形式复古，无异于_______，甚至会把国学弄成与现代文明相对抗的姿态，凡事不问好坏对错，一切以东西古今划界。凡是古人的都是好的，哪怕骑驴；凡是现代的都是“非我族类”，都该保持距离。如此下去，国学非但不会被这些人发扬光大，相反可能会走入狭隘化、极端化、边缘化的境地，钻进狭小天地里________，与文明发展割断脉络，把自己变成了一块“化石”。</p><ol><li>依次填入划横线部分最恰当的一项是：</li><li>A.缘木求鱼 蓬荜生辉</li><li>B.掩耳盗铃 纤尘不染</li><li>C.刻舟求剑 皮里阳秋</li><li>D.买椟还珠 孤芳自赏</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">此题第一空不易判断，可先从第二空入手，由文段“凡是古人的都是好的······凡是现代的都是‘非我族类’”、“钻进狭小天地里”可知，所填词语应体现出贬义色彩，表达国学比较“自负”的意思。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“蓬荜生辉”形容贵客来访令主人感到增光不少，为谦辞;</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">B项“纤尘不染”现泛指丝毫不受坏习惯、坏风气的影响，也用来形容非常清洁、干净，含褒义；</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">C项“皮里阳秋”意思是藏在心里不说出来的言论，为中性词。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项、B项和C项均与文段感情色彩不一致，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项“孤芳自赏”比喻自命清高、自我欣赏或自命不凡，贬义，符合文意。答案锁定D项。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二步，验证第一空。“买椟还珠”比喻没有眼光，取舍不当，对应前文“停留在如此浅层次的形式复古”，符合文意。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">因此，选择D选项。</li></ol></details><p><strong>例</strong>：（2010国家）“诗是不可译的，中国古典诗歌更是不可译。”爱好古典诗歌的中国人，包括不少作家、学者、翻译家常常如是说，语气中带着七分________三分________。然而，话说回来，如果没有翻译，中国古典诗歌如何走出国门、走向世界呢?</p><ol><li>依次填入划横线部分最恰当的一项是( )。</li><li>A.自豪 遗憾</li><li>B.无奈 悲伤</li><li>C.感伤 埋怨</li><li>D.骄傲 惭愧</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="5" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">此语境中的关键信息为“爱好古典诗歌的中国人”，既然是爱好者，那第一个表示七分的主流感情色彩就应该用积极的词语，因此CD排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">继续看第二个语境，既然是积极的语境，那消极的词也应该用程度轻的，“遗憾”和“惭愧”进行对比，“遗憾”更为合适，所以这道题的正确答案为A。</li></ol></details><h2 id="五、适用范围" tabindex="-1">五、适用范围 <a class="header-anchor" href="#五、适用范围" aria-label="Permalink to “五、适用范围”">​</a></h2><ol><li><p><strong>1</strong>、有些词语或成语有使用对象，只能用于特定的人或物。用于人的还有老幼尊卑之分，用于物的还有抽象具体之别。</p><ol><li>（1）范围大小：比如边疆和边境都指靠近国境的地区，但边疆的范围比边境大。</li><li>（2）搭配对象：比如爱护用于对人或物的保护，是上对下。爱戴只能用于人，且限于下对上。</li><li>（3）语境适用：比如安之若素指面对不顺利的境况仍能像平常一样，而随遇而安则强调在任何环境中都安然自得。</li><li>（4）抽象具体：比如“采用”适用对象广，可以是抽象，也可以是具体；“采纳”适用对象窄，一般用于某些抽象事物。</li></ol></li><li><p><strong>2、具体运用(巧用组词法)</strong>：适用范围就是找词语运用的环境，这类词语一般都是我们较熟悉的词，所以，在做题时如果是区别两个词的适用范围，我们可以用组词法。利用空前空后判断词语是否适合。</p><ol><li><p><code>例如</code>：让这些_____的幸福陪伴在身边，如影随形。我们日复一日奔波在平凡的生活中，似乎忘了停下来感受一下生活中的点滴幸福。【微小 细小】</p></li><li><blockquote><p>在这个语境中，空处所跟的对象是“幸福”，一个抽象名词。微小和细小含义其实差不太多。但是细小是指窄、体积小的实物，我们一般都会说“细小的某种物体”，跟的是具体名词，而微小生活中一般和抽象名词一起用居多，比如“微小的希望”、“微小的幸福”等。所以在这个语境当中，很显然，用微小更合适。</p></blockquote></li></ol></li></ol><p><strong>例</strong>：(2019国考)中国的传统文化中，“老”是一个褒义的字眼。一个年轻人处事得当，会被说老练、老成。但是进入互联网特别是移动互联网时代，这沿袭了数千年的观念，短短数十年_______。年龄大、资历老逐渐不再是一种优势，有时反而成了学习新事物的一种_______。</p><ol><li>依次填入画横线部分最恰当的一项是：</li><li>A. 土崩瓦解 羁绊  B. 灰飞烟灭 累赘</li><li>C. 化为乌有 阻力  D. 分崩离析 弊端</li></ol>',62)),l("details",d,[l("ol",g,[o[4]||(o[4]=l("li",{style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none"}},"第一空，横线处所填成语与 “观念” 搭配，由转折关联词 “但是” 可知，文段强调 “老” 是褒义的这一传统观念，在互联网时代不再被人们认同，被逐渐瓦解。",-1)),o[5]||(o[5]=l("li",{style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}},"A项 “土崩瓦解” 指像土崩塌，瓦破碎一样，不可收拾，比喻事物的分裂，置于此处用以强调旧观念的瓦解，符合文意；",-1)),o[6]||(o[6]=l("li",{style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}},"B项 “灰飞烟灭” 比喻事物消失净尽、C项 “化为乌有” 指全部消失或完全落空，置于此处程度过重，文段并未体现 “老是褒义的字眼” 这一观念已完全消失，与文意不符，排除；",-1)),l("li",_,[o[1]||(o[1]=i("D项",-1)),o[2]||(o[2]=l("span",null," ",-1)),p(e,{color:"bulu",style:{"box-sizing":"border-box"}},{default:a(()=>[...o[0]||(o[0]=[i("“分崩离析”，通常搭配具体是事物，我们经常说的“这个国家最终分崩离析”，与 抽象的“观念” 搭配不当",-1)])]),_:1}),o[3]||(o[3]=i("，排除。",-1))]),o[7]||(o[7]=l("li",{style:{"box-sizing":"border-box","overflow-wrap":"break-word","list-style":"none","margin-top":"8px"}},"第二空，代入验证，“反而”提示反向递进，“羁绊”指束缚牵制，与前文的“优势”构成对应，符合文意，当选。 故正确答案为A。",-1))])]),o[9]||(o[9]=r('<p><strong>例</strong>：(2021广东)正是广大基层干部群众以无比巨大的热情投入改革，以只争朝夕的劲头______改革，以一往无前的勇气探路改革，才令改革开放的大潮澎湃不息，蔚为壮观，______出令世界惊叹的成就。</p><ol><li>依次填入画横线部分最恰当的一项是：</li><li>A. 推动 创建  B. 参与 创造</li><li>C. 推进 构建  D. 参加 制造</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="4" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">第一空，横线处搭配“改革”且对应“以一往无前的勇气探路改革”，根据逻辑上的顺承关系，应先“加入改革”，再“探路改革”，故横线处要体现出“加入”的语义，B项“参与”、D项“参加”均符合文意，即对改革有热情、积极参与、进而探路改革，逻辑通顺，保留。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">A项“推动”指使事物前进，C项“推进”指向前进，填入横线处与后文矛盾，应该是先“加入”，再“探路”，从而“推进、推动”，均排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">第二空，横线处搭配“成就”，B项“创造出令世界惊叹的成就”，符合文意，当选。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D项“制造”一指用人工使原材料成为可供使用的物品，如制造机器、制造化肥；或指人为地造成某种气氛或局面等（含贬义），如制造纠纷、制造紧张气氛，与“成就”搭配不当，排除。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故正确答案为B。</li></ol></details><p><strong>例</strong>：（2015四川泸州市事业单位）在过去六十年中，现代中国的建设走过一条_____道路，经历过无数艰辛、动荡、摇摆与反复，既有山重水复之_____，也有柳暗花明之转机。</p><ol><li>填入横线部分最恰当的一项是：</li><li>A.循环往复 迷惘</li><li>B.迂回曲折 困惑</li><li>C.艰难险阻 迷惑</li><li>D.跌宕起伏 困难</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="6" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">第一填空为题目突破口，由题意推知此处应填一个包含“艰辛、摇摆、反复等”含义的词语。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">能够快速排除只表示艰辛的“艰难险阻”、只表示动荡的“跌宕起伏”和只表示摇摆与反复的“循环往复”，由此快速定位选择词义范围大的词“迂回曲折”。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">故答案就是B。</li></ol></details><p><strong>例</strong>：（2010吉林）不同历史发展阶段，不同地域的人们，由于生活经验的范围和性质不同，所________而形成的思维框架、思维模式也就不同。</p><ol><li>填入横线部分最恰当的一项是（ ）。</li><li>A.沉淀</li><li>B.积淀</li><li>C.积累</li><li>D.发展</li></ol><details class="details custom-block" open="" style="box-sizing:border-box;border:1px solid rgba(0, 0, 0, 0);border-radius:8px;padding:16px 16px 8px;line-height:24px;font-size:16px;color:rgb(223, 223, 214);background-color:rgba(142, 150, 170, 0.14);margin:0px !important;"><ol start="6" style="box-sizing:border-box;list-style:decimal;margin:16px 0px;padding:0px 0px 0px 1.25rem;"><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;">积淀有积累和沉淀的意思，所以B选项语义范围最大，当选B。</li><li style="box-sizing:border-box;overflow-wrap:break-word;list-style:none;margin-top:8px;">D选项属于逻辑错误，应该先“形成”后“发展”所以排除D。</li></ol></details>',9))])}const u=s(x,[["render",w]]);export{v as __pageData,u as default};
